// Validate and normalize the incoming URL
const input = $input.first().json;
const body = input.body || input;

const url = (body.url || '').trim();
if (!url) {
  throw new Error('Missing required field: url');
}

// Basic URL validation using regex (URL constructor not available in sandbox)
const urlPattern = /^https?:\/\/[^\s/$.?#].[^\s]*$/i;
if (!urlPattern.test(url)) {
  throw new Error(`Invalid URL format: ${url}`);
}

// Normalize: remove trailing slash, remove fragment
let normalized = url.split('#')[0].replace(/\/+$/, '');

return [{
  json: {
    url: normalized,
    tags: body.tags || [],
    category: body.category || '',
    title: body.title || ''
  }
}];

// Validate scraped content and extract metadata
const scrapeResult = $input.first().json;
const inputData = $('Validate URL').first().json;

// Extract markdown content
const data = scrapeResult.data || scrapeResult;
const markdown = data.markdown || '';
const metadata = data.metadata || {};

if (markdown.length < 100) {
  return [{
    json: {
      valid: false,
      error: `Content too short (${markdown.length} chars). Minimum 100 chars required.`,
      url: inputData.url
    }
  }];
}

// Use provided title, or extract from metadata, or from content
let title = inputData.title;
if (!title) {
  title = metadata.title || metadata.ogTitle || '';
}
if (!title) {
  // Extract first heading from markdown
  const headingMatch = markdown.match(/^#\s+(.+)$/m);
  if (headingMatch) {
    title = headingMatch[1].trim();
  }
}
if (!title) {
  title = 'Untitled';
}

// Generate filename from title
const filename = title
  .replace(/[^a-zA-Z0-9\u4e00-\u9fff\s-]/g, '')
  .replace(/\s+/g, '-')
  .substring(0, 80) + '.md';

// Extract keywords from title for tag matching
const keywords = title
  .replace(/[^a-zA-Z0-9\u4e00-\u9fff\s]/g, ' ')
  .split(/\s+/)
  .filter(w => w.length > 1)
  .slice(0, 10);

return [{
  json: {
    valid: true,
    content: markdown,
    title: title,
    filename: filename,
    url: inputData.url,
    tags: inputData.tags,
    category: inputData.category,
    keywords: keywords
  }
}];

// Merge matched tags with user-provided tags
const matchResult = $input.first().json;
const contentData = $('Validate Content').first().json;

const matchedTags = (matchResult.tags || matchResult.matched || []).map(t => typeof t === 'string' ? t : t.name || t.tag || '');
const userTags = contentData.tags || [];

// Combine and deduplicate
const allTags = [...new Set([...userTags, ...matchedTags])].filter(t => t);

return [{
  json: {
    content: contentData.content,
    filename: contentData.filename,
    title: contentData.title,
    url: contentData.url,
    tags: allTags,
    category: contentData.category
  }
}];
